// Check if a city belongs to any of the target regions
function cityMatchesRegions(city: string, targetRegions: string[]): boolean {
  if (!city || !targetRegions || targetRegions.length === 0) return false;
  for (const region of targetRegions) {
    // Direct match: city name equals region name (e.g., Lisboa district, Lisboa city)
    if (region === city) return true;
    // Check mapping
    const regionCities = REGION_CITIES_MAP[region];
    if (regionCities && regionCities.some(rc => rc === city)) return true;
  }
  return false;
}

export const useStoreAds = () => {
  const { t } = useTranslation();
  const queryClient = useQueryClient();

  const adsQuery = useQuery({
    queryKey: ["store-ads"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("store_ads" as any)
        .select("*")
        .order("sort_order", { ascending: false })
        .order("created_at", { ascending: false });
      if (error) throw error;
      return data as unknown as StoreAd[];
    },
  });

  const createAd = useMutation({
    mutationFn: async (ad: StoreAdInsert) => {
      const { error } = await supabase.from("store_ads" as any).insert(ad as any);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["store-ads"] });
      toast({ title: t("common.success"), description: "商店广告创建成功" });
    },
    onError: (error: Error) => {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    },
  });

  const updateAd = useMutation({
    mutationFn: async ({ id, ...updates }: StoreAdUpdate & { id: string }) => {
      const { error } = await supabase.from("store_ads" as any).update(updates as any).eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["store-ads"] });
      toast({ title: t("common.success"), description: "商店广告更新成功" });
    },
    onError: (error: Error) => {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    },
  });

  const deleteAd = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("store_ads" as any).delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["store-ads"] });
      toast({ title: t("common.success"), description: "商店广告删除成功" });
    },
    onError: (error: Error) => {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    },
  });

  return { ...adsQuery, createAd, updateAd, deleteAd };
};

// Hook for frontend: get active store ads for a specific country and city
export const useActiveStoreAds = (country: string | null, city: string | null = null) => {
  return useQuery({
    queryKey: ["active-store-ads", country, city],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("store_ads" as any)
        .select("*")
        .eq("is_active", true)
        .eq("global_enabled", true)
        .order("sort_order", { ascending: false });
      if (error) throw error;
      
      const now = new Date();
      
      // Map country full names to codes for matching
      const countryNameToCode: Record<string, string> = {
        'Portugal': 'PT', 'portugal': 'PT',
        'Spain': 'ES', 'spain': 'ES',
        'France': 'FR', 'france': 'FR',
        'Germany': 'DE', 'germany': 'DE',
        'Italy': 'IT', 'italy': 'IT',
        'United Kingdom': 'GB', 'UK': 'GB', 'uk': 'GB',
        'Netherlands': 'NL', 'netherlands': 'NL',
        'China': 'CN', 'china': 'CN',
        'USA': 'US', 'United States': 'US',
        'Brazil': 'BR', 'brazil': 'BR',
        'Japan': 'JP', 'japan': 'JP',
        'Austria': 'AT', 'Australia': 'AU',
        'New Zealand': 'NZ', 'Hungary': 'HU',
        'Belgium': 'BE', 'Luxembourg': 'LU',
        'Czech Republic': 'CZ', 'Denmark': 'DK',
        'Norway': 'NO', 'Ireland': 'IE',
        'Greece': 'GR', 'Turkey': 'TR',
        'Croatia': 'HR', 'Morocco': 'MA',
        'Argentina': 'AR', 'Colombia': 'CO',
        'Peru': 'PE', 'Mexico': 'MX', 'Ecuador': 'EC',
        'Thailand': 'TH', 'Vietnam': 'VN',
        'Singapore': 'SG', 'Malaysia': 'MY',
        'Taiwan': 'TW', 'Korea': 'KR', 'South Korea': 'KR',
        'Macau': 'MO', 'macau': 'MO',
        'UAE': 'AE', 'Saudi Arabia': 'SA',
        'South Africa': 'ZA', 'Ethiopia': 'ET',
        'Georgia': 'GE', 'Armenia': 'AM', 'Azerbaijan': 'AZ',
        'Mongolia': 'MN', 'Nepal': 'NP', 'Pakistan': 'PK',
        'Myanmar': 'MM', 'Laos': 'LA', 'Cambodia': 'KH',
        'Canada': 'CA', 'Monaco': 'MC',
        'Mozambique': 'MZ', 'Angola': 'AO',
        'Tunisia': 'TN', 'Uzbekistan': 'UZ',
      };
      
      const normalizedCountry = country ? (countryNameToCode[country] || country).toUpperCase() : null;
      
      return (data as unknown as StoreAd[]).filter(ad => {
        // Check date range
        if (ad.start_date && new Date(ad.start_date) > now) return false;
        if (ad.end_date && new Date(ad.end_date) < now) return false;
        
        const hasCountryTarget = ad.target_countries && ad.target_countries.length > 0;
        const hasRegionTarget = ad.target_regions && ad.target_regions.length > 0;
        const hasCityTarget = ad.target_cities && ad.target_cities.length > 0;
        
        // No targeting at all = global, show everywhere
        if (!hasCountryTarget && !hasRegionTarget && !hasCityTarget) return true;
        
        // --- Country level check ---
        if (hasCountryTarget && normalizedCountry) {
          const countryMatch = ad.target_countries.some(tc => tc.toUpperCase() === normalizedCountry);
          if (!countryMatch) return false;
          
          // Country matches. Now check region/city refinement
          // If has region targeting, check if the restaurant's city falls within a target region
          if (hasRegionTarget && city) {
            const regionMatch = cityMatchesRegions(city, ad.target_regions);
            if (regionMatch) return true;
            // Region doesn't match, but maybe city targeting does
            if (hasCityTarget) {
              return ad.target_cities.some(tc => tc === city);
            }
            return false; // Region set but city not in any target region
          }
          if (hasRegionTarget && !city) return false; // Has region filter but no city info
          
          // No region targeting, check city targeting
          if (hasCityTarget && city) {
            return ad.target_cities.some(tc => tc === city);
          }
          if (hasCityTarget && !city) return false;
          
          // Country matches, no region/city filter = nationwide
          return true;
        }
        
        if (hasCountryTarget && !normalizedCountry) return false;
        
        // No country targeting but has region/city targeting
        if (hasRegionTarget && city) {
          return cityMatchesRegions(city, ad.target_regions);
        }
        if (hasCityTarget && city) {
          return ad.target_cities.some(tc => tc === city);
        }
        
        return false;
      });
    },
    staleTime: 1000 * 60 * 5,
  });
};
